ysql.PrivilegeType\n227: \tColumnPriv mysql.PrivilegeType\n228: }\n229: \n230: type columnsPrivRecord struct {\n231: \tbaseRecord\n232: \n233: \tDB         string\n234: \tTableName  string\n235: \tColumnName string\n236: \tTimestamp  time.Time\n237: \tColumnPriv mysql.PrivilegeType\n238: }\n239: \n240: // defaultRoleRecord is used to cache mysql.default_roles\n241: type defaultRoleRecord struct {\n242: \tbaseRecord\n243: \n244: \tDefaultRoleUser string\n245: \tDefaultRoleHost string\n246: }\n247: \n248: // roleGraphEdgesTable is used to cache relationship between and role.\n249: type roleGraphEdgesTable struct {\n250: \troleList map[string]*auth.RoleIdentity\n251: }\n252: \n253: // Find method is used to find role from table\n254: func (g roleGraphEdgesTable) Find(user, host string) bool {\n255: \tif host == \"\" {\n256: \t\thost = \"%\"\n257: \t}\n258: \tkey := user + \"@\" + host\n259: \tif g.roleList == nil {\n260: \t\treturn false\n261: \t}\n262: \t_, ok := g.roleList[key]\n263: \treturn ok\n264: }\n265: \n266: type immutable struct {\n267: \tuser         []UserRecord\n268: \tdb           []dbRecord\n269: \ttablesPriv   []tablesPrivRecord\n270: \tcolumnsPriv  []columnsPrivRecord\n271: \tdefaultRoles []defaultRoleRecord\n272: \n273: \tglobalPriv  []globalPrivRecord\n274: \tdynamicPriv []dynamicPrivRecord\n275: \troleGraph   map[string]roleGraphEdgesTable\n276: }\n277: \n278: type extended struct {\n279: \tUserMap       map[string][]UserRecord // Accelerate User searching\n280: \tGlobal        map[string][]globalPrivRecord\n281: \tDynamic       map[string][]dynamicPrivRecord\n282: \tDBMap         map[string][]dbRecord         // Accelerate DB searching\n283: \tTablesPrivMap map[string][]tablesPrivRecord // Accelerate TablesPriv searching\n284: }\n285: \n286: // MySQLPrivilege is the in-memory cache of mysql privilege tables.\n287: type MySQLPrivilege struct {\n288: \t// In MySQL, a user identity consists of a user + host.\n289: \t// Either portion of user or host 