390: 			return errLoadPrivilege.FastGen("mysql.roles")
391: 		}
392: 		logutil.BgLogger().Warn("mysql.default_roles missing")
393: 	}
394: 
395: 	err = p.LoadColumnsPrivTable(ctx)
396: 	if err != nil {
