644: 	xEnd := strings.HasSuffix(x, `%`)
645: 	yEnd := strings.HasSuffix(y, `%`)
646: 	if xEnd || yEnd {
647: 		switch {
648: 		case !xEnd && yEnd:
649: 			return -1
650: 		case xEnd && !yEnd:
651: 			return 1
652: 		case xEnd && yEnd:
653: 			// 192.168.199.% smaller than 192.168.%
654: 			// A not very accurate comparison, compare them by length.
655: 			if len(x) > len(y) {
656: 				return -1
657: 			}
658: 		}
659: 		return 0
660: 	}
661: 
662: 	// For other case, the order is nondeterministic.
663: 	switch x < y {
664: 	case true:
665: 		return -1
666: 	case false:
667: 		return 1
668: 	}
669: 	return 0
670: }
