{"meta": null, "content": [{"type": "text", "text": "{"content":"700: \treturn nil\n701: }\n702: \n703: // LoadDBTable loads the mysql.db table from database.\n704: func (p *MySQLPrivilege) LoadDBTable(ctx sqlexec.RestrictedSQLExecutor) error {\n705: \terr := p.loadTable(ctx, sqlLoadDBTable, p.decodeDBTableRow)\n706: \tif err != nil {\n707: \t\treturn err\n708: \t}\n709: \tp.buildDBMap()\n710: \treturn nil\n711: }\n712: \n713: func compareDBRecord(x, y dbRecord) int {\n714: \treturn compareBaseRecord(\u0026x.baseRecord, \u0026y.baseRecord)\n715: }\n716: \n717: func (p *MySQLPrivilege) buildDBMap() {\n718: \tdbMap := make(map[string][]dbRecord, len(p.db))\n719: \tfor _, record := range p.db {\n720: \t\tdbMap[record.User] = append(dbMap[record.User], record)\n721: \t}\n722: \n723: \t// Sort the records to make the matching rule work.\n724: \tfor _, records := range dbMap {\n725: \t\tslices.SortFunc(records, compareDBRecord)\n726: \t}\n727: \tp.DBMap = dbMap\n728: }\n729: \n730: func (p *MySQLPrivilege) buildDynamicMap() {\n731: \tdynamic := make(map[string][]dynamicPrivRecord)\n732: \tfor _, value := range p.dynamicPriv {\n733: \t\tdynamic[value.User] = append(dynamic[value.User], value)\n734: \t}\n735: \tp.Dynamic = dynamic\n736: }\n737: \n738: // LoadTablesPrivTable loads the mysql.tables_priv table from database.\n739: func (p *MySQLPrivilege) LoadTablesPrivTable(ctx sqlexec.RestrictedSQLExecutor) error {\n740: \terr := p.loadTable(ctx, sqlLoadTablePrivTable, p.decodeTablesPrivTableRow)\n741: \tif err != nil {\n742: \t\treturn err\n743: \t}\n744: \tp.buildTablesPrivMap()\n745: \treturn nil\n746: }\n747: \n748: func (p *MySQLPrivilege) buildTablesPrivMap() {\n749: \ttablesPrivMap := make(map[string][]tablesPrivRecord, len(p.tablesPriv))\n750: \tfor _, record := range p.tablesPriv {\n751: \t\ttablesPrivMap[record.User] = append(tablesPrivMap[record.User], record)\n752: \t}\n753: \tp.TablesPrivMap = tablesPrivMap\n754: }\n755: \n756: // LoadColumnsPrivTable loads the mysql.columns_priv table from database.\n757: func (p *MySQLPrivilege) LoadColumnsPrivTable(ctx sqlexec.RestrictedSQLExecutor) error {\n758: \treturn p.loadTable(ctx, sqlLoadColumnsPrivTable, p.decodeColumnsPrivTableRow)\n759: }\n760: \n761: // LoadDefaultRoles loads the mysql.columns_priv table from database.\n762: func (p *MySQLPrivilege) LoadDefaultRoles(ctx sqlexec.RestrictedSQLExecutor) error {\n763: \treturn p.loadTable(ctx, sqlLoadDefaultRoles, p.decodeDefaultRoleTableRow)\n764: }\n765: \n766: func addUserFilterCondition(sql string, userList []string) string {\n767: \tif len(userList) == 0 {\n768: \t\treturn sql\n769: \t}\n770: \tvar b strings.Builder\n771: \tb.WriteString(sql)\n772: \tb.WriteString(\" WHERE \")\n773: \tfor i, user := range userList {\n774: \t\tif i \u003e 0 {\n775: \t\t\tb.WriteString(\" OR \")\n776: \t\t}\n777: \t\tfmt.Fprintf(\u0026b, \"USER = '%s'\", sqlescape.EscapeString(user))\n778: \t}\n779: \treturn b.String()\n780: }\n781: \n782: func (p *immutable) loadTable(sctx sqlexec.RestrictedSQLExecutor, sql string,\n783: \tdecodeTableRow func(chunk.Row, []*resolve.ResultField) error, userList ...string) error {\n784: \tctx := kv.WithInternalSourceType(context.Background(), kv.InternalTxnPrivilege)\n785: \tsql = addUserFilterCondition(sql, userList)\n786: \trows, fs, err := sctx.ExecRestrictedSQL(ctx, nil, sql)\n787: \tif err != nil {\n788: \t\treturn errors.Trace(err)\n789: \t}\n790: \tfor _, row := range rows {\n791: \t\t// NOTE: decodeTableRow decodes data from a chunk Row, that is a shallow copy.\n792: \t\t// The result will reference memory in the chunk, so the chunk must not be reused\n793: \t\t// here, otherwise some werid bug will happen!\n794: \t\terr = decodeTableRow(row, fs)\n795: \t\tif err != nil {\n796: \t\t\treturn errors.Trace(err)\n797: \t\t}\n798: \t}\n799: \treturn nil\n800: }\n801: \n802: // parseHostIPNet parses an IPv4 address and its subnet mask (e.g. `127.0.0.0/255.255.255.0`),\n803: // return the `IPNet` struct which represent the IP range info (e.g. `127.0.0.1 ~ 127.0.0.255`).\n804: // `IPNet` is used to check if a giving IP (e.g. `127.0.0.1`) is in its IP range by call `IPNet.Contains(ip)`.\n805: func parseHostIPNet(s string) *net.IPNet {\n806: \ti := strings.IndexByte(s, '/')\n807: \tif i \u003c 0 {\n808: \t\treturn nil\n809: \t}\n810: \thostIP := net.ParseIP(s[:i]).To4()\n811: \tif hostIP == nil {\n812: \t\treturn nil\n813: \t}\n814: \tmaskIP := net.ParseIP(s[i+1:]).To4()\n815: \tif maskIP == nil {\n816: \t\treturn nil\n817: \t}\n818: \tmask := net.IPv4Mask(maskIP[0], maskIP[1], maskIP[2], maskIP[3])\n819: \t// We must ensure that: \u003chost_ip\u003e \u0026 \u003cnetmask\u003e == \u003chost_ip\u003e\n820: \t// e.g. `127.0.0.1/255.0.0.0` is an illegal string,\n821: \t// because `127.0.0.1` \u0026 `255.0.0.0` == `127.0.0.0`, but != `127.0.0.1`\n822: \t// see https://dev.mysql.com/doc/refman/5.7/en/account-names.html\n823: \tif !hostIP.Equal(hostIP.Mask(mask)) {\n824: \t\treturn nil\n825: \t}\n826: \treturn \u0026net.IPNet{\n827: \t\tIP:   hostIP,\n828: \t\tMask: mask,\n829: \t}\n830: }\n831: \n832: func (record *baseRecord) assignUserOrHost(row chunk.Row, i int, f *resolve.ResultField) {\n833: \tswitch f.ColumnAsName.L {\n834: \tcase \"user\":\n835: \t\trecord.User = row.GetString(i)\n836: \tcase \"host\":\n837: \t\trecord.Host = row.GetString(i)\n838: \t\trecord.patChars, record.patTypes = stringutil.CompilePatternBinary(record.Host, '\\\\')\n839: \t\trecord.hostIPNet = parseHostIPNet(record.Host)\n840: \t}\n841: }\n842: \n843: func (p *immutable) decodeUserTableRow(row chunk.Row, fs []*resolve.ResultField) error {\n844: \tvar value UserRecord\n845: \tfor i, f := range fs {\n846: \t\tswitch {\n847: \t\tcase f.ColumnAsName.L == \"authentication_string\":\n848: \t\t\tvalue.AuthenticationString = row.GetString(i)\n849: \t\tcase f.ColumnAsName.L == \"account_locked\":\n850: \t\t\tif row.GetEnum(i).String() == \"Y\" {\n851: \t\t\t\tvalue.AccountLocked = true\n852: \t\t\t}\n853: \