1310: // RequestDynamicVerification checks all roles for a specific DYNAMIC privilege.
1311: func (p *MySQLPrivilege) RequestDynamicVerification(activeRoles []*auth.RoleIdentity, user, host string, privName string, withGrant bool) bool {
1312: 	privName = strings.ToUpper(privName)
1313: 	if p.HasExplicitlyGrantedDynamicPrivilege(activeRoles, user, host, privName, withGrant) {
1314: 		return true
1315: 	}
1316: 	// If SEM is enabled, and the privilege is of type restricted, do not fall through
1317: 	// To using SUPER as a replacement privilege.
1318: 	if sem.IsEnabled() && sem.IsRestrictedPrivilege(privName) {
1319: 		return false
1320: 	}
1321: 
1322: 	// For compatibility reasons, the SUPER privilege also has all DYNAMIC privileges granted to it (dynamic privs are a super replacement)
1323: 	// This may be changed in future, but will require a bootstrap task to assign all dynamic privileges
1324: 	// to users with SUPER, otherwise tasks such as BACKUP and ROLE_ADMIN will start to fail.
1325: 	// The visitInfo system will also need modification to support OR conditions.
1326: 	if withGrant && !p.RequestVerification(activeRoles, user, host, "", "", "", mysql.GrantPriv) {
1327: 		return false
1328: 	}
1329: 	return p.RequestVerification(activeRoles, user, host, "", "", "", mysql.SuperPriv)
1330: }
