1332: // RequestVerification checks whether the user have sufficient privileges to do the operation.
1333: func (p *MySQLPrivilege) RequestVerification(activeRoles []*auth.RoleIdentity, user, host, db, table, column string, priv mysql.PrivilegeType) bool {
1334: 	if priv == mysql.UsagePriv {
1335: 		return true
1336: 	}
1337: 
1338: 	roleList := p.FindAllUserEffectiveRoles(user, host, activeRoles)
1339: 	roleList = append(roleList, &auth.RoleIdentity{Username: user, Hostname: host})
1340: 
1341: 	var userPriv, dbPriv, tablePriv, columnPriv mysql.PrivilegeType
1342: 	for _, r := range roleList {
1343: 		userRecord := p.matchUser(r.Username, r.Hostname)
1344: 		if userRecord != nil {
1345: 			userPriv |= userRecord.Privileges
1346: 		}
1347: 	}
1348: 	if userPriv&priv > 0 {
1349: 		return true
1350: 	}
1351: 
1352: 	for _, r := range roleList {
1353: 		dbRecord := p.matchDB(r.Username, r.Hostname, db)
1354: 		if dbRecord != nil {
1355: 			dbPriv |= dbRecord.Privileges
1356: 		}
1357: 	}
1358: 	if dbPriv&priv > 0 {
1359: 		return true
1360: 	}
1361: 
1362: 	for _, r := range roleList {
1363: 		tableRecord := p.matchTables(r.Username, r.Hostname, db, table)
1364: 		if tableRecord != nil {
1365: 			tablePriv |= tableRecord.TablePriv
1366: 			if column != "" {
1367: 				columnPriv |= tableRecord.ColumnPriv
1368: 			}
1369: 		}
1370: 	}
1371: 	if tablePriv&priv > 0 || columnPriv&priv > 0 {
1372: 		return true
1373: 	}
1374: 
1375: 	columnPriv = 0
1376: 	for _, r := range roleList {
1377: 		columnRecord := p.matchColumns(r.Username, r.Hostname, db, table, column)
1378: 		if columnRecord != nil {
1379: 			columnPriv |= columnRecord.ColumnPriv
1380: 		}
1381: 	}
1382: 	if columnPriv&priv > 0 {
1383: 		return true
1384: 	}
1385: 
1386: 	return priv == 0
1387: }
