1389: // DBIsVisible checks whether the user can see the db.
1390: func (p *MySQLPrivilege) DBIsVisible(user, host, db string) bool {
1391: 	if record := p.matchUser(user, host); record != nil {
1392: 		if record.Privileges&globalDBVisible > 0 {
1393: 			return true
1394: 		}
1395: 		// For metrics_schema, `PROCESS` can also work.
1396: 		if record.Privileges&mysql.ProcessPriv > 0 && strings.EqualFold(db, util.MetricSchemaName.O) {
1397: 			return true
1398: 		}
1399: 	}
1400: 
1401: 	// INFORMATION_SCHEMA is visible to all users.
1402: 	if strings.EqualFold(db, "INFORMATION_SCHEMA") {
1403: 		return true
1404: 	}
1405: 
1406: 	if record := p.matchDB(user, host, db); record != nil {
1407: 		if record.Privileges > 0 {
1408: 			return true
1409: 		}
1410: 	}
1411: 
1412: 	for _, record := range p.tablesPriv {
1413: 		if record.baseRecord.match(user, host) &&
1414: 			strings.EqualFold(record.DB, db) {
1415: 			if record.TablePriv != 0 || record.ColumnPriv != 0 {
1416: 				return true
1417: 			}
1418: 		}
1419: 	}
1420: 
1421: 	for _, record := range p.columnsPriv {
1422: 		if record.baseRecord.match(user, host) &&
1423: 			strings.EqualFold(record.DB, db) {
1424: 			if record.ColumnPriv != 0 {
1425: 				return true
1426: 			}
1427: 		}
1428: 	}
1429: 
1430: 	return false
1431: }
