358: // GetDBTableInfo gets the accessed dbs and tables info.
359: func GetDBTableInfo(visitInfo []visitInfo) []stmtctx.TableEntry {
360: 	var tables []stmtctx.TableEntry
361: 	existsFunc := func(tbls []stmtctx.TableEntry, tbl *stmtctx.TableEntry) bool {
362: 		for _, t := range tbls {
363: 			if t == *tbl {
364: 				return true
365: 			}
366: 		}
367: 		return false
368: 	}
369: 	for _, v := range visitInfo {
370: 		if v.db == "" && v.table == "" {
371: 			// when v.db == "" and v.table == "", it means this visitInfo is for dynamic privilege,
372: 			// so it is not related to any database or table.
373: 			continue
374: 		}
375: 
376: 		tbl := &stmtctx.TableEntry{DB: v.db, Table: v.table}
377: 		if !existsFunc(tables, tbl) {
378: 			tables = append(tables, *tbl)
379: 		}
380: 	}
381: 	return tables
382: }
