622: func (b *PlanBuilder) buildDo(ctx context.Context, v *ast.DoStmt) (base.Plan, error) {
623: 	var p base.LogicalPlan
624: 	dual := logicalop.LogicalTableDual{RowCount: 1}.Init(b.ctx, b.getSelectOffset())
625: 	dual.SetSchema(expression.NewSchema())
626: 	p = dual
627: 	proj := logicalop.LogicalProjection{Exprs: make([]expression.Expression, 0, len(v.Exprs))}.Init(b.ctx, b.getSelectOffset())
628: 	proj.SetOutputNames(make([]*types.FieldName, len(v.Exprs)))
629: 	schema := expression.NewSchema(make([]*expression.Column, 0, len(v.Exprs))...)
630: 
631: 	// Since do statement only contain expression list, and it may contain aggFunc, detecting to build the aggMapper firstly.
632: 	var (
633: 		err      error
634: 		aggFuncs []*ast.AggregateFuncExpr
635: 		totalMap map[*ast.AggregateFuncExpr]int
636: 	)
637: 	hasAgg := b.detectAggInExprNode(v.Exprs)
638: 	needBuildAgg := hasAgg
639: 	if hasAgg {
640: 		if b.buildingRecursivePartForCTE {
641: 			return nil, plannererrors.ErrCTERecursiveForbidsAggregation.GenWithStackByArgs(b.genCTETableNameForError())
642: 		}
643: 
644: 		aggFuncs, totalMap = b.extractAggFuncsInExprs(v.Exprs)
645: 
646: 		if len(aggFuncs) == 0 {
647: 			needBuildAgg = false
648: 		}
649: 	}
650: 	if needBuildAgg {
651: 		var aggIndexMap map[int]int
652: 		p, aggIndexMap, err = b.buildAggregation(ctx, p, aggFuncs, nil, nil)
653: 		if err != nil {
654: 			return nil, err
655: 		}
656: 		for agg, idx := range totalMap {
657: 			totalMap[agg] = aggIndexMap[idx]
658: 		}
659: 	}
660: 
661: 	for _, astExpr := range v.Exprs {
662: 		expr, np, err := b.rewrite(ctx, astExpr, p, totalMap, true)
663: 		if err != nil {
664: 			return nil, err
665: 		}
666: 		p = np
667: 		proj.Exprs = append(proj.Exprs, expr)
668: 		schema.Append(&expression.Column{
669: 			UniqueID: b.ctx.GetSessionVars().AllocPlanColumnID(),
670: 			RetType:  expr.GetType(b.ctx.GetExprCtx().GetEvalCtx()),
671: 		})
672: 	}
673: 	proj.SetChildren(p)
674: 	proj.SetSelf(proj)
675: 	proj.SetSchema(schema)
676: 	proj.CalculateNoDelay = true
677: 	return proj, nil
678: }
