3687: func collectVisitInfoFromRevokeStmt(sctx base.PlanContext, vi []visitInfo, stmt *ast.RevokeStmt) ([]visitInfo, error) {
3688: 	// To use REVOKE, you must have the GRANT OPTION privilege,
3689: 	// and you must have the privileges that you are granting.
3690: 	dbName := stmt.Level.DBName
3691: 	tableName := stmt.Level.TableName
3692: 	// This supports a local revoke SELECT on tablename, but does
3693: 	// not add dbName to the visitInfo of a *.* grant.
3694: 	if dbName == "" && stmt.Level.Level != ast.GrantLevelGlobal {
3695: 		if sctx.GetSessionVars().CurrentDB == "" {
3696: 			return nil, plannererrors.ErrNoDB
3697: 		}
3698: 		dbName = sctx.GetSessionVars().CurrentDB
3699: 	}
3700: 	var nonDynamicPrivilege bool
3701: 	var allPrivs []mysql.PrivilegeType
3702: 	for _, item := range stmt.Privs {
3703: 		if item.Priv == mysql.ExtendedPriv {
3704: 			vi = appendDynamicVisitInfo(vi, []string{strings.ToUpper(item.Name)}, true, nil) // verified in MySQL: requires the dynamic grant option to revoke.
3705: 			continue
3706: 		}
3707: 		nonDynamicPrivilege = true
3708: 		if item.Priv == mysql.AllPriv {
3709: 			switch stmt.Level.Level {
3710: 			case ast.GrantLevelGlobal:
3711: 				allPrivs = mysql.AllGlobalPrivs
3712: 			case ast.GrantLevelDB:
3713: 				allPrivs = mysql.AllDBPrivs
3714: 			case ast.GrantLevelTable:
3715: 				allPrivs = mysql.AllTablePrivs
3716: 			}
3717: 			break
3718: 		}
3719: 		vi = appendVisitInfo(vi, item.Priv, dbName, tableName, "", nil)
3720: 	}
3721: 
3722: 	for _, priv := range allPrivs {
3723: 		vi = appendVisitInfo(vi, priv, dbName, tableName, "", nil)
3724: 	}
3725: 	for _, u := range stmt.Users {
3726: 		// For SEM, make sure the users are not restricted
3727: 		vi = appendVisitInfoIsRestrictedUser(vi, sctx, u.User, "RESTRICTED_USER_ADMIN")
3728: 	}
3729: 	if nonDynamicPrivilege {
3730: 		// Dynamic privileges use their own GRANT OPTION. If there were any non-dynamic privilege requests,
3731: 		// we need to attach the "GLOBAL" version of the GRANT OPTION.
3732: 		vi = appendVisitInfo(vi, mysql.GrantPriv, dbName, tableName, "", nil)
3733: 	}
